    19→declare(strict_types=1);
    20→
    21→namespace Dev\Controller;
    22→
    23→use Exception;
    24→use SAML2\Message;
    25→use SAML2\Response as SamlResponse;
    26→use SAML2\StatusResponse;
    27→use Symfony\Bundle\FrameworkBundle\Controller\AbstractController;
    28→use Symfony\Component\HttpFoundation\Response;
    29→use Symfony\Component\Routing\Annotation\Route;
    30→use DOMDocument;
    31→use RobRichards\XMLSecLibs\XMLSecurityKey;
    32→use SAML2\Assertion;
    33→use SAML2\Certificate\PrivateKeyLoader;
    34→use SAML2\Configuration\PrivateKey;
    35→use SAML2\DOMDocumentFactory;
    36→use Surfnet\SamlBundle\Entity\IdentityProvider;
    37→use Surfnet\SamlBundle\Entity\ServiceProvider;
    38→use Surfnet\SamlBundle\Http\Exception\AuthnFailedSamlResponseException;
    39→use Surfnet\SamlBundle\Http\PostBinding;
    40→use Surfnet\SamlBundle\SAML2\AuthnRequest;
    41→use Surfnet\SamlBundle\SAML2\AuthnRequestFactory;
    42→use Symfony\Component\HttpFoundation\RedirectResponse;
    43→use Symfony\Component\HttpFoundation\Request;
    44→
    45→/**
    46→ * Demo SP.
    47→ */
    48→final class SPController extends AbstractController
    49→{
    50→    public function __construct(
    51→        private readonly ServiceProvider $serviceProvider,
    52→        private readonly IdentityProvider $identityProvider,
    53→        private readonly PostBinding $postBinding
    54→    ) {
    55→    }
    56→
    57→    #[Route(path: '/', name: 'homepage', methods: ['GET'])]
    58→    public function homepage(): Response
    59→    {
    60→        return $this->redirectToRoute('sp_demo');
    61→    }
    62→
    63→    #[Route(path: '/demo/sp', name: 'sp_demo', methods: ['GET', 'POST'])]
    64→    public function demoSp(Request $request): Response
    65→    {
    66→        if (!$request->isMethod(Request::METHOD_POST)) {
    67→            return $this->render('dev/sp.html.twig', ['nameId' => $request->get('nameId')]);
    68→        }
    69→        $authnRequest = AuthnRequestFactory::createNewRequest($this->serviceProvider, $this->identityProvider);
    70→
    71→        // Set nameId when we want to authenticate.
    72→        if ($request->get('action') === 'authenticate') {
    73→            $authnRequest->setSubject($request->get('NameID'));
    74→        }
    75→
    76→        // Build request query parameters.
    77→        $requestAsXml = $authnRequest->getUnsignedXML();
    78→        $encodedRequest = base64_encode(gzdeflate($requestAsXml));
    79→        $queryParams = [AuthnRequest::PARAMETER_REQUEST => $encodedRequest];
    80→        $relayState = $request->get(AuthnRequest::PARAMETER_RELAY_STATE);
    81→        if (!empty($relayState)) {
    82→            $queryParams[AuthnRequest::PARAMETER_RELAY_STATE] = $relayState;
    83→        }
    84→
    85→        // Create redirect response.
    86→        $query = $this->signRequestQuery($queryParams);
    87→        $url = sprintf('%s?%s', $this->identityProvider->getSsoUrl(), $query);
    88→        $response = new RedirectResponse($url);
    89→
    90→        // Set Stepup request id header.
    91→        $stepupRequestId = $request->get('X-Stepup-Request-Id');
    92→        if (!empty($stepupRequestId)) {
    93→            $response->headers->set('X-Stepup-Request-Id', $stepupRequestId);
    94→        }
    95→
    96→        return $response;
    97→    }
    98→
    99→    #[Route(path: '/demo/sp/acs', name: 'sp_demo_acs', methods: ['POST'])]
   100→    public function assertionConsumerService(Request $request): Response
   101→    {
   102→        $xmlResponse = $request->request->get('SAMLResponse');
   103→        $xml = base64_decode($xmlResponse);
   104→        try {
   105→            /** @var Assertion $response */
   106→            $response = $this->postBinding->processResponse($request, $this->identityProvider, $this->serviceProvider);
   107→
   108→            $nameID = $response->getNameId();
   109→
   110→            return $this->render('dev/acs.html.twig', [
   111→                'requestId' => $response->getId(),
   112→                'nameId' => $nameID instanceof \SAML2\XML\saml\NameID ? [
   113→                    'value' => $nameID->getValue(),
   114→                    'format' => $nameID->getFormat(),
   115→                ] : [],
   116→                'issuer' => $response->getIssuer(),
   117→                'relayState' => $request->get(AuthnRequest::PARAMETER_RELAY_STATE, ''),
   118→                'authenticatingAuthority' => $response->getAuthenticatingAuthority(),
   119→                'xml' => $this->toFormattedXml($xml),
   120→            ]);
   121→        } catch (AuthnFailedSamlResponseException $e) {
   122→            $samlResponse = $this->toUnsignedErrorResponse($xml);
   123→
   124→            return $this->render('dev/acs-error-response.html.twig', [
   125→                'error' => $e->getMessage(),
   126→                'status' => $samlResponse->getStatus(),
   127→                'requestId' => $samlResponse->getId(),
   128→                'issuer' => $samlResponse->getIssuer(),
   129→                'relayState' => $request->get(AuthnRequest::PARAMETER_RELAY_STATE, ''),
   130→                'xml' => $this->toFormattedXml($xml),
   131→            ]);
   132→        }
   133→    }
   134→
   135→    /**
   136→     * Formats xml.
   137→     */
   138→    private function toFormattedXml(string $xml): string|false
   139→    {
   140→        $domXml = new DOMDocument('1.0');
   141→        $domXml->preserveWhiteSpace = false;
   142→        $domXml->formatOutput = true;
   143→        $domXml->loadXML($xml);
   144→
   145→        return $domXml->saveXML();
   146→    }
   147→
   148→    /**
   149→     * Sign AuthnRequest query parameters.
   150→     * @throws Exception
   151→     */
   152→    private function signRequestQuery(array $queryParams): string
   153→    {
   154→        $securityKey = $this->loadServiceProviderPrivateKey();
   155→        $queryParams[AuthnRequest::PARAMETER_SIGNATURE_ALGORITHM] = $securityKey->type;
   156→        $toSign = http_build_query($queryParams);
   157→        $signature = $securityKey->signData($toSign);
   158→
   159→        return $toSign.'&Signature='.urlencode(base64_encode((string) $signature));
   160→    }
   161→
   162→    /**
   163→     * Loads the private key from the service provider.
   164→     *
   165→     * @throws Exception
   166→     */
   167→    private function loadServiceProviderPrivateKey(): XMLSecurityKey
   168→    {
   169→        $keyLoader = new PrivateKeyLoader();
   170→        $privateKey = $keyLoader->loadPrivateKey(
   171→            $this->serviceProvider->getPrivateKey(PrivateKey::NAME_DEFAULT)
   172→        );
   173→        $key = new XMLSecurityKey(XMLSecurityKey::RSA_SHA256, ['type' => 'private']);
   174→        $key->loadKey($privateKey->getKeyAsString());
   175→
   176→        return $key;
   177→    }
   178→
   179→    /**
   180→     * @throws Exception
   181→     */
   182→    private function toUnsignedErrorResponse(string $xml): StatusResponse
   183→    {
   184→        $previous = libxml_disable_entity_loader(true);
   185→        $asXml = DOMDocumentFactory::fromString($xml);
   186→        libxml_disable_entity_loader($previous);
   187→
   188→        /** @var StatusResponse $statusResponse */
   189→        $statusResponse = SamlResponse::fromXML($asXml->documentElement);
   190→        return $statusResponse;
   191→    }
   192→}
